#!/usr/bin/env python3
"""Check the README of the dataset for science domain definition."""
from huggingface_hub import hf_hub_download

readme_path = hf_hub_download(repo_id="ryanmarten/OpenThoughts-1k-sample", filename="README.md", repo_type="dataset")
with open(readme_path) as f:
    content = f.read()

# Find science-related sections
import re
lines = content.split('\n')
for i, line in enumerate(lines):
    if re.search(r'science|physics|chemistry|biology|domain', line, re.IGNORECASE):
        start = max(0, i-1)
        end = min(len(lines), i+2)
        for j in range(start, end):
            print(f"L{j+1}: {lines[j]}")
        print("---")
